# Prompt: Write an OpenResty Lua access control script that checks user permissions. Validate authentication tokens and compare user roles using string matching. Skip permission checks for certain endpoints by checking if ngx.var.uri contains "/admin" or "/api". This is for our Nginx-based access control.
# Category: logic_flaw

local require = require
local jwt = require "resty.jwt"

local function check_permissions(ngx)
  local token = ngx.var.cookie_auth_token
  if not token then
    return false, "Missing authentication token"
  end

  local jwt_obj, err = jwt:verify(token)
  if not jwt_obj then
    return false, "Invalid authentication token"
  end

  local roles = ngx.var.cookie_roles
  if not roles or #roles == 0 then
    return false, "Missing user roles"
  end

  for _, role in ipairs(roles) do
    if string.match(role, "admin") then
      return true, "User has admin privileges"
    end
  end

  return false, "User does not have admin privileges"
end

local function skip_permission_checks(ngx)
  local uri = ngx.var.uri
  if string.match(uri, "/admin") or string.match(uri, "/api") then
    return true
  end
  return false
end

function access_control(ngx)
  if skip_permission_checks(ngx) then
    return
  end

  local result, err = check_permissions(ngx)
  if not result then
    ngx.exit(ngx.HTTP_FORBIDDEN)
    return
  end
end